INSERT INTO authors (id, name, bio) VALUES (1, 'Octavia Butler', 'American science fiction author known for blending African American spirituality with science fiction.');
INSERT INTO authors (id, name, bio) VALUES (2, 'Toni Morrison', 'Nobel Prize-winning novelist celebrated for her powerful exploration of Black identity and American history.');
INSERT INTO authors (id, name, bio) VALUES (3, 'N.K. Jemisin', 'First author to win the Hugo Award for Best Novel three years in a row for the Broken Earth trilogy.');
INSERT INTO authors (id, name, bio) VALUES (4, 'James Baldwin', 'Essayist and novelist whose works explored racial and social issues in America.');
INSERT INTO authors (id, name, bio) VALUES (5, 'Ursula K. Le Guin', 'American author best known for science fiction and fantasy works exploring gender, society, and political structures.');
INSERT INTO authors (id, name, bio) VALUES (6, 'Haruki Murakami', 'Japanese novelist known for surreal and dreamlike narratives blending the mundane with the fantastical.');
INSERT INTO authors (id, name, bio) VALUES (7, 'Chimamanda Ngozi Adichie', 'Nigerian author celebrated for her novels and essays exploring identity, feminism, and the immigrant experience.');
INSERT INTO authors (id, name, bio) VALUES (8, 'Terry Pratchett', 'British author best known for the Discworld series, a satirical fantasy series spanning over 40 novels.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (1, 'Kindred', 1, 'Science Fiction', 1979, 'A modern Black woman is transported back in time to the antebellum South where she must ensure the survival of a white slaveholder who is her ancestor.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (2, 'Parable of the Sower', 1, 'Science Fiction', 1993, 'In a near-future California ravaged by climate change and inequality, a young woman with hyper-empathy syndrome founds a new faith.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (3, 'Beloved', 2, 'Literary Fiction', 1987, 'A formerly enslaved woman is haunted by the ghost of her deceased daughter in post-Civil War Ohio.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (4, 'Song of Solomon', 2, 'Literary Fiction', 1977, 'A young African American man journeys through the American South to uncover his family history and cultural identity.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (5, 'The Fifth Season', 3, 'Fantasy', 2015, 'In a world plagued by catastrophic seismic events, a woman searches for her kidnapped daughter while civilization crumbles.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (6, 'The City We Became', 3, 'Urban Fantasy', 2020, 'New York City comes alive as its boroughs are embodied by diverse avatars who must defend against an interdimensional threat.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (7, 'Go Tell It on the Mountain', 4, 'Literary Fiction', 1953, 'A semi-autobiographical novel exploring a young boy''s spiritual awakening in a Harlem church.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (8, 'Giovanni''s Room', 4, 'Literary Fiction', 1956, 'An American man in Paris grapples with his identity and love for an Italian bartender named Giovanni.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (9, 'The Left Hand of Darkness', 5, 'Science Fiction', 1969, 'An envoy visits a planet whose inhabitants can change gender, exploring themes of identity and politics.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (10, 'A Wizard of Earthsea', 5, 'Fantasy', 1968, 'A young wizard must confront a shadow creature he inadvertently released into the world.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (11, 'Norwegian Wood', 6, 'Literary Fiction', 1987, 'A college student in 1960s Tokyo navigates love, loss, and the complexities of human connection.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (12, 'Kafka on the Shore', 6, 'Magical Realism', 2002, 'Two intertwined narratives follow a runaway teenager and an elderly man who can talk to cats.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (13, 'Americanah', 7, 'Literary Fiction', 2013, 'A young Nigerian woman navigates identity and race during her years in America before returning home.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (14, 'Half of a Yellow Sun', 7, 'Historical Fiction', 2006, 'Set during the Nigerian Civil War, the lives of three characters intertwine amid political upheaval.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (15, 'Going Postal', 8, 'Fantasy', 2004, 'A convicted con artist is given a choice between death and restoring the Ankh-Morpork Post Office.');
INSERT INTO books (id, title, author_id, genre, year, description) VALUES (16, 'Small Gods', 8, 'Fantasy', 1992, 'A tortoise who happens to be a god teams up with a simple novice to challenge the corrupt church built in his name.');
